# frozen_string_literal: true

require 'swagger_helper'

# rubocop:disable RSpec/EmptyExampleGroup, RSpec/VariableName
RSpec.describe 'Authentication API', type: :request do
  # ===========================================================================
  # POST /api/v1/auth/register
  # ===========================================================================

  path '/api/v1/auth/register' do
    post 'Register a new user' do
      tags 'Authentication'
      consumes 'application/json'
      produces 'application/json'

      parameter name: :body, in: :body, schema: {
        type: :object,
        properties: {
          email: { type: :string, format: :email, example: 'user@example.com' },
          password: { type: :string, minLength: 14, example: 'securepassword14chars' }
        },
        required: %w[email password]
      }

      response '201', 'Account created successfully' do
        schema type: :object,
               properties: {
                 message: { type: :string },
                 user: { '$ref' => '#/components/schemas/user' },
                 access_token: { type: :string },
                 refresh_token: { type: :string }
               }

        let(:body) { { email: 'newuser@example.com', password: 'securepassword14chars' } }
        run_test!
      end

      response '422', 'Validation errors' do
        schema '$ref' => '#/components/schemas/validation_errors'

        let(:body) { { email: 'invalid', password: 'short' } }
        run_test!
      end
    end
  end

  # ===========================================================================
  # POST /api/v1/auth/login
  # ===========================================================================

  path '/api/v1/auth/login' do
    post 'Authenticate user' do
      tags 'Authentication'
      consumes 'application/json'
      produces 'application/json'

      parameter name: :body, in: :body, schema: {
        type: :object,
        properties: {
          email: { type: :string, format: :email, example: 'user@example.com' },
          password: { type: :string, example: 'securepassword14chars' }
        },
        required: %w[email password]
      }

      response '200', 'Login successful' do
        schema type: :object,
               properties: {
                 message: { type: :string },
                 user: { '$ref' => '#/components/schemas/user' },
                 access_token: { type: :string },
                 refresh_token: { type: :string }
               }

        let!(:credential) { create(:auth_credential, email: 'test@example.com', password: 'correctpassword14') }
        let(:body) { { email: 'test@example.com', password: 'correctpassword14' } }
        run_test!
      end

